import { describe, it, expect, vi } from 'vitest'

// Mock createFileRoute so we can import the handler without the full router
vi.mock('@tanstack/react-router', () => ({
  createFileRoute: () => (opts: any) => opts,
}))

import { getHealthResponse } from './health'

describe('GET /api/health', () => {
  it('returns a 200 Response', () => {
    const response = getHealthResponse()
    expect(response).toBeInstanceOf(Response)
    expect(response.status).toBe(200)
  })

  it('returns { status: "ok" } in JSON body', async () => {
    const response = getHealthResponse()
    const data = await response.json()
    expect(data.status).toBe('ok')
  })

  it('returns a valid ISO 8601 timestamp', async () => {
    const response = getHealthResponse()
    const data = await response.json()
    expect(data.timestamp).toBeDefined()
    expect(new Date(data.timestamp).toISOString()).toBe(data.timestamp)
  })

  it('returns uptime_seconds as a non-negative integer', async () => {
    const response = getHealthResponse()
    const data = await response.json()
    expect(typeof data.uptime_seconds).toBe('number')
    expect(data.uptime_seconds).toBeGreaterThanOrEqual(0)
    expect(Number.isInteger(data.uptime_seconds)).toBe(true)
  })
})

